// ─── GENERATION ─────────────────────────────────────────────────────────

function generateRecipes(): Recipe[] {
  const all: Recipe[] = [...SEED_RECIPES]

  Object.entries(BASES).forEach(([cat, items]) => {
    items.forEach((item, i) => {
      all.push({
        name: item.name,
        emoji: item.emoji,
        description: item.desc,
        category: cat as Recipe['category'],
        cuisine: item.cuisine,
        prepTime: item.time,
        ageRange: AGE_RANGES[i % AGE_RANGES.length],
        nutrients: item.nutrients,
        ingredients: item.ings,
        instructions: item.steps,
      })
    })
  })

  return all
}

